import{_ as s,o as i,c as a,a2 as n}from"./chunks/framework.CGYl2SZ_.js";const e=JSON.parse('{"title":"typing indicators","description":"typing indicators 页面","frontmatter":{"title":"typing indicators","description":"typing indicators 页面"},"headers":[],"relativePath":"concepts/typing-indicators.md","filePath":"concepts/typing-indicators.md"}');const t=s({name:"concepts/typing-indicators.md"},[["render",function(s,e,t,l,o,h){return i(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="打字指示器" tabindex="-1">打字指示器 <a class="header-anchor" href="#打字指示器" aria-label="Permalink to &quot;打字指示器&quot;">​</a></h1><h1 id="打字指示器-1" tabindex="-1">打字指示器 <a class="header-anchor" href="#打字指示器-1" aria-label="Permalink to &quot;打字指示器&quot;">​</a></h1><p>打字指示器在运行活跃时发送到聊天渠道。使用 <code>agents.defaults.typingMode</code> 控制<strong>何时</strong>开始打字，使用 <code>typingIntervalSeconds</code> 控制<strong>多久</strong>刷新一次。</p><h2 id="默认值" tabindex="-1">默认值 <a class="header-anchor" href="#默认值" aria-label="Permalink to &quot;默认值&quot;">​</a></h2><p>当 <code>agents.defaults.typingMode</code> <strong>未设置</strong>时，OpenClaw 保持旧版行为：</p><ul><li><strong>直接聊天</strong>：模型循环一旦开始，打字立即开始。</li><li><strong>带提及的群组聊天</strong>：打字立即开始。</li><li><strong>不带提及的群组聊天</strong>：仅当消息文本开始流式传输时，打字才开始。</li><li><strong>心跳运行</strong>：打字被禁用。</li></ul><h2 id="模式" tabindex="-1">模式 <a class="header-anchor" href="#模式" aria-label="Permalink to &quot;模式&quot;">​</a></h2><p>将 <code>agents.defaults.typingMode</code> 设置为以下之一：</p><ul><li><code>never</code> — 永远不显示打字指示器。</li><li><code>instant</code> — <strong>模型循环一旦开始</strong>就立即开始打字，即使运行稍后只返回静默回复令牌。</li><li><code>thinking</code> — 在<strong>第一个推理增量</strong>时开始打字（需要运行的 <code>reasoningLevel: &quot;stream&quot;</code>）。</li><li><code>message</code> — 在<strong>第一个非静默文本增量</strong>时开始打字（忽略 <code>NO_REPLY</code> 静默令牌）。</li></ul><p>&quot;多早触发&quot;的顺序： <code>never</code> → <code>message</code> → <code>thinking</code> → <code>instant</code></p><h2 id="配置" tabindex="-1">配置 <a class="header-anchor" href="#配置" aria-label="Permalink to &quot;配置&quot;">​</a></h2><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    typingMode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;thinking&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    typingIntervalSeconds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">6</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>您可以按会话覆盖模式或节奏：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  session</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    typingMode</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;message&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    typingIntervalSeconds</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">4</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><ul><li><code>message</code> 模式不会为仅静默回复显示打字（例如用于抑制输出的 <code>NO_REPLY</code> 令牌）。</li><li><code>thinking</code> 仅在运行流式传输推理时触发（<code>reasoningLevel: &quot;stream&quot;</code>）。如果模型不发出推理增量，打字不会开始。</li><li>无论模式如何，心跳从不显示打字。</li><li><code>typingIntervalSeconds</code> 控制<strong>刷新节奏</strong>，而不是开始时间。默认是 6 秒。</li></ul>',16)])])}]]);export{e as __pageData,t as default};
